  ('dietitian-moex-00895', 'dietitian', 'dietitian-moex-111-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '依教育部公告之「學校午餐食物內容及營養基準」，下列關於國小一至三年級學童學校午餐設計之 敘述，何者錯誤？', '["豆製品供應每週不得超過2份", "每日未精緻全穀根莖類之供應量應占主食1/3以上", "全穀根莖類替代品（甜不辣、米血糕等）供應每週不得超過2份", "魚肉類半成品（各式丸類、香腸、重組雞塊等）供應每週不得超過1份"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "78915ad3adb1", "answer_pdf_sha1": "b45a61057a81", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00896', 'dietitian', 'dietitian-moex-111-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列為評估學校午餐膳食接受度之方法，在執行上何者是了解用膳者接受度最快速、最方便的方 法？', '["膳後問卷調查", "供應量統計", "觀察及廚餘回收量統計", "與用膳者進行面對面訪談"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "78915ad3adb1", "answer_pdf_sha1": "b45a61057a81", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00897', 'dietitian', 'dietitian-moex-111-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列關於食物量之敘述，何者正確？', '["AP（aspurchased）是指供應量", "EP（edibleportion）是指熟品可食量", "生廢棄率＝（AP-EP）／EP100%", "收縮率＝（生品重-熟品重）／生品重100%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "78915ad3adb1", "answer_pdf_sha1": "b45a61057a81", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00898', 'dietitian', 'dietitian-moex-111-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列烹調方法，何者較不適用在團膳製備？', '["炸", "蒸", "烤", "煎"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "78915ad3adb1", "answer_pdf_sha1": "b45a61057a81", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
