  ('dietitian-moex-00900', 'dietitian', 'dietitian-moex-111-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '醫院健檢中心需採購早餐給健檢者，承辦單位將採購品項、數量、價位和早餐需送達之時間等需 求與資格公開刊登於資訊網站，並依政府採購法訂定合約之程序進行，此採購法稱為：', '["比價採購", "招標採購", "牌價收購", "議價採購"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "78915ad3adb1", "answer_pdf_sha1": "b45a61057a81", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
