  ('dietitian-moex-00902', 'dietitian', 'dietitian-moex-111-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '採購包裝食品應注意食品標示，下列敘述何者錯誤？', '["外包裝及小包裝皆須完整標示", "應標示含基因改造食品原料及過敏原食品", "蛋白質、脂肪、脂肪酸、碳水化合物、糖、膳食纖維標示單位為公克", "不論包裝食品或散裝食品國內通過農產品生產驗證者，應標示可追溯之來源"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "78915ad3adb1", "answer_pdf_sha1": "b45a61057a81", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
